### **P0-3: 实现 RealtimeService 广播逻辑** ⏰ 0.5天

**任务**: 完善 WebSocket 服务

**文件**: `src/dashboard/services/realtime.service.ts`

```typescript
export class RealtimeService {
  private clients: Set<WebSocket> = new Set();
  private subscriptions: Map<WebSocket, Set<string>> = new Map();

  // 添加客户端
  addClient(socket: WebSocket) {
    this.clients.add(socket);

    socket.on('close', () => {
      this.removeClient(socket);
    });
  }

  // 移除客户端
  removeClient(socket: WebSocket) {
    this.clients.delete(socket);
    this.subscriptions.delete(socket);
  }

  // 订阅频道
  subscribe(socket: WebSocket, channel: string) {
    if (!this.subscriptions.has(socket)) {
      this.subscriptions.set(socket, new Set());
    }
    this.subscriptions.get(socket)!.add(channel);
  }

  // 广播消息
  broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data });

    this.clients.forEach(socket => {
      if (socket.readyState === 1) { // WebSocket.OPEN
        socket.send(message);
      }
    });
  }

  // 心跳检测
  startHeartbeat(interval = 30000) {
    setInterval(() => {
      this.broadcast('ping', { timestamp: Date.now() });
    }, interval);
  }
}
```

