### **P1-5: 完善前端 API 集成** ⏰ 1天

**任务**: 前端正确调用后端 API

**文件**: `dashboard/src/api/dashboard.ts`

```typescript
import axios from 'axios';

const API_BASE = 'http://localhost:3000/api';

export const dashboardAPI = {
  // 获取系统概览
  async getOverview() {
    const { data } = await axios.get(`${API_BASE}/system/overview`);
    return data;
  },

  // 获取迭代列表
  async getIterations(params?: any) {
    const { data } = await axios.get(`${API_BASE}/iterations`, { params });
    return data;
  },

  // 获取当前迭代
  async getCurrentIteration() {
    const { data } = await axios.get(`${API_BASE}/iterations/current`);
    return data;
  },

  // 获取 Agent 状态
  async getAgents() {
    const { data } = await axios.get(`${API_BASE}/agents`);
    return data;
  }
};
```

**WebSocket 连接**:
```typescript
// dashboard/src/services/websocket.ts
export class DashboardWebSocket {
  private ws: WebSocket | null = null;

  connect(url = 'ws://localhost:3000/api/ws') {
    this.ws = new WebSocket(url);

    this.ws.onmessage = (event) => {
      const { event, data } = JSON.parse(event.data);

      // 处理不同事件
      switch (event) {
        case 'iteration.started':
          console.log('迭代开始:', data);
          break;
        case 'agent.status_changed':
          console.log('Agent 状态变更:', data);
          break;
        case 'iteration.completed':
          console.log('迭代完成:', data);
          break;
      }
    };
  }
}
```

